import{_ as t,o as e,c as s,a2 as n}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"依赖与版本","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dependencies.md","filePath":"guide/dependencies.md","lastUpdated":1783543150000}'),d={name:"guide/dependencies.md"};function i(l,a,r,p,o,c){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="依赖与版本" tabindex="-1">依赖与版本 <a class="header-anchor" href="#依赖与版本" aria-label="Permalink to &quot;依赖与版本&quot;">​</a></h1><p>GT 系列会尽量兼容多版本服务端和多种生态插件，但每个服务器环境都不同。安装前先理解依赖关系，后面排错会轻松很多。</p><h2 id="服务端核心" tabindex="-1">服务端核心 <a class="header-anchor" href="#服务端核心" aria-label="Permalink to &quot;服务端核心&quot;">​</a></h2><p>推荐：</p><ul><li>Paper</li><li>Purpur</li><li>Spigot 兼容核心</li></ul><p>不建议在正式服直接使用非常冷门或魔改严重的核心。<br> 如果一定要用，先在测试服跑完整功能。</p><h2 id="java-版本" tabindex="-1">Java 版本 <a class="header-anchor" href="#java-版本" aria-label="Permalink to &quot;Java 版本&quot;">​</a></h2><p>低版本 Minecraft 往往使用 Java 8，高版本通常使用 Java 17 或更高。<br> 如果你在 1.12.2 这类老版本使用插件，要特别注意：</p><ul><li>插件是否使用了过高版本 Java 编译。</li><li>依赖库是否支持 Java 8。</li><li>脚本引擎是否会加载不兼容的实现。</li></ul><h2 id="软依赖" tabindex="-1">软依赖 <a class="header-anchor" href="#软依赖" aria-label="Permalink to &quot;软依赖&quot;">​</a></h2><p>软依赖不是每个服都必须安装，但装了以后插件会自动接入更多功能。</p><table tabindex="0"><thead><tr><th>类型</th><th>常见插件</th><th>GT 系列用途</th></tr></thead><tbody><tr><td>怪物</td><td>MythicMobs</td><td>怪物掉落、MM 物品、Boss 玩法</td></tr><tr><td>物品库</td><td>NeigeItems、ItemsAdder、Oraxen、CraftEngine</td><td>读取自定义物品</td></tr><tr><td>属性</td><td>AttributePlus、CraneAttribute、SX-Attribute</td><td>掉落加成、宝石属性、伤害显示</td></tr><tr><td>变量</td><td>PlaceholderAPI</td><td>条件、显示文本、动态倍率</td></tr><tr><td>显示</td><td>Adyeshach、ProtocolLib、PacketEvents</td><td>实体显示、血条、发包能力</td></tr><tr><td>经济</td><td>Vault、XConomy</td><td>金币扣除、兑换、宝石成本</td></tr></tbody></table><h2 id="安装顺序建议" tabindex="-1">安装顺序建议 <a class="header-anchor" href="#安装顺序建议" aria-label="Permalink to &quot;安装顺序建议&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础依赖 / 生态插件</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>GTCore</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>GT 系列业务插件</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>修改配置并重启</span></span></code></pre></div><p>如果业务插件在 GTCore 前加载，可能会出现找不到 API、命令注册失败、适配器未初始化等问题。</p><h2 id="检查依赖是否启用" tabindex="-1">检查依赖是否启用 <a class="header-anchor" href="#检查依赖是否启用" aria-label="Permalink to &quot;检查依赖是否启用&quot;">​</a></h2><p>进入服务器后输入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugins</span></span></code></pre></div><p>确认相关插件是绿色。<br> 如果某个依赖是红色，先修它，不要继续排 GT 插件。</p>`,19)])])}const b=t(d,[["render",i]]);export{u as __pageData,b as default};
